file.content:
/* ── Interest Sections: horizontal scroll cards ── */
.interest-sections{
    display: flex;
    flex-direction: column;
    gap: 1.25rem;
    padding: 0.5rem 0;
}

.interest-section{
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.interest-section-header{
    display: flex;
    align-items: center;
    padding: 0 0.85rem;
}

.interest-section-title{
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 700;
    letter-spacing: 0.03rem;
    text-transform: uppercase;
    color: var(--text-secondary);
}

/* ── Scroll track wrapper (for arrow positioning) ── */
.interest-section-track{
    position: relative;
}

/* ── Scroll arrows ── */
.interest-scroll-arrow{
    position: absolute;
    top: 50%;
    transform: translateY(-50%);
    z-index: 5;
    display: flex;
    align-items: center;
    justify-content: center;
    width: 32px;
    height: 32px;
    border-radius: 50%;
    border: 1px solid var(--border-card);
    background: var(--bg-elevated);
    color: var(--text-secondary);
    cursor: pointer;
    box-shadow: 0 2px 8px rgba(80, 60, 40, 0.1);
    opacity: 0;
    transition: opacity 0.2s ease, background 0.15s ease, color 0.15s ease, border-color 0.15s ease, transform 0.15s ease;
}
.interest-section-track:hover .interest-scroll-arrow{
    opacity: 1;
}
.interest-scroll-arrow:hover{
    background: var(--bg-primary);
    color: rgba(212, 168, 83, 1);
    border-color: rgba(212, 168, 83, 0.3);
    transform: translateY(-50%) scale(1.08);
    box-shadow: 0 3px 12px rgba(80, 60, 40, 0.14);
}
.interest-scroll-arrow:active{
    transform: translateY(-50%) scale(0.95);
}
.interest-scroll-arrow-left{
    left: 4px;
}
.interest-scroll-arrow-right{
    right: 4px;
}
[data-theme="dark"] .interest-scroll-arrow{
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.25);
}

/* ── Horizontal scroll track ── */
.interest-section-scroll{
    display: flex;
    gap: 0.75rem;
    overflow-x: auto;
    scroll-snap-type: x mandatory;
    -webkit-overflow-scrolling: touch;
    padding: 0.25rem 0.85rem 0.5rem 0.85rem;
    scrollbar-width: thin;
    scrollbar-color: transparent transparent;
    transition: scrollbar-color 0.2s ease;
}
.interest-section-scroll:hover{
    scrollbar-color: rgba(0,0,0,0.15) transparent;
}
[data-theme="dark"] .interest-section-scroll:hover{
    scrollbar-color: rgba(255,255,255,0.15) transparent;
}
.interest-section-scroll::-webkit-scrollbar{
    height: 4px;
}
.interest-section-scroll::-webkit-scrollbar-track{
    background: transparent;
}
.interest-section-scroll::-webkit-scrollbar-thumb{
    background: transparent;
    border-radius: 4px;
    transition: background 0.2s ease;
}
.interest-section-scroll:hover::-webkit-scrollbar-thumb{
    background: rgba(0,0,0,0.15);
}
[data-theme="dark"] .interest-section-scroll:hover::-webkit-scrollbar-thumb{
    background: rgba(255,255,255,0.15);
}

/* ── Card ── */
.interest-card{
    flex: 0 0 220px;
    scroll-snap-align: start;
    display: flex;
    flex-direction: column;
    border-radius: 12px;
    border: 1px solid var(--border-card);
    background: var(--bg-secondary);
    overflow: hidden;
    cursor: pointer;
    transition: transform 0.18s ease, box-shadow 0.18s ease;
}
.interest-card:hover{
    transform: translateY(-2px);
    box-shadow: 0 4px 16px rgba(0,0,0,0.1);
}
.interest-card:active{
    transform: scale(0.98);
}

/* ── Card image ── */
.interest-card-image{
    width: 100%;
    height: 110px;
    overflow: hidden;
}
.interest-card-image img{
    width: 100%;
    height: 100%;
    object-fit: cover;
}

/* ── Card body ── */
.interest-card-body{
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
    padding: 0.6rem 0.7rem 0.7rem;
}

.interest-card-title{
    font-family: var(--font-heading, var(--font-ui));
    font-size: 0.82rem;
    font-weight: 650;
    line-height: 1.3;
    color: var(--text-primary);
    margin: 0;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.interest-card-excerpt{
    font-family: var(--font-body, var(--font-ui));
    font-size: 0.72rem;
    line-height: 1.4;
    color: var(--text-secondary);
    margin: 0;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.interest-card-meta{
    display: flex;
    align-items: center;
    gap: 0.3rem;
    font-family: var(--font-ui);
    font-size: 0.65rem;
    color: var(--text-faint);
    margin-top: 0.15rem;
}

.interest-card-author{
    font-weight: 600;
}

.interest-card-dot{
    opacity: 0.5;
}

/* ── Mobile ── */
@media(max-width: 600px){
    .interest-scroll-arrow{
        display: none;
    }
    .interest-section-scroll{
        scrollbar-width: none;
        -ms-overflow-style: none;
    }
    .interest-section-scroll::-webkit-scrollbar{
        display: none;
    }
    .interest-card{
        flex: 0 0 180px;
    }
    .interest-card-image{
        height: 90px;
    }
    .interest-card-body{
        padding: 0.5rem 0.55rem 0.6rem;
    }
